// LAYER 1+2: Extract & Validate (§4.1 PRE-validate)
// Zero-throw: returns Standard Contract error, never throws

const raw = $input.first().json;
const input = (raw.body && typeof raw.body === 'object') ? raw.body : raw;

function isPositiveInt(str) { const n = Number(str); return Number.isInteger(n) && n > 0 && String(n) === String(str).trim(); }
function isNonNegativeInt(str) { const n = Number(str); return Number.isInteger(n) && n >= 0 && String(n) === String(str).trim(); }
function isSafeStr(str) { if (!str || str.length > 255) return false; for(let i=0; i<str.length; i++) { const c = str[i]; if (c === "'" || c === '"' || c === ";" || c === '\\') return false; } return true; }

// STRICT ISO 8601 with timezone validation
function isIsoDate(str) {
  // Must have T and timezone (Z or ±HH:MM)
  if (!str || !str.includes('T')) return false;
  const tzMatch = str.match(/(Z|[+-]\d{2}:\d{2})$/);
  if (!tzMatch) return false;

  const d = new Date(str);
  if (isNaN(d.getTime())) return false;

  // Verify date components match (catches Feb 30 → Mar 02 normalization)
  const parts = str.match(/^(\d{4})-(\d{2})-(\d{2})T/);
  if (!parts) return false;
  const [_, year, month, day] = parts;
  if (parseInt(month) !== d.getUTCMonth() + 1) return false;
  if (parseInt(day) !== d.getUTCDate()) return false;

  return true;
}

function ve(code, msg) {
  return [{ json: {
    ...raw,
    success: false, error_code: code, error_message: msg, data: null,
    _meta: { source: 'DB_Create_Booking', timestamp: new Date().toISOString(), workflow_id: $workflow.id },
    _exit_early: true
  }}];
}

const idempotency_key = String(input.idempotency_key || '').trim();
if (!idempotency_key) return ve('MISSING_FIELD', 'idempotency_key is required');
if (!isSafeStr(idempotency_key)) return ve('INVALID_INPUT', 'idempotency_key contains invalid characters or exceeds 255 chars');

const pidStr = String(input.provider_id ?? '').trim();
if (!pidStr || !isPositiveInt(pidStr)) return ve('INVALID_TYPE', 'provider_id must be a positive integer');
const provider_id = parseInt(pidStr);
if (provider_id < 1) return ve('INVALID_TYPE', 'provider_id must be >= 1');

const sidStr = String(input.service_id ?? '').trim();
if (!sidStr || !isPositiveInt(sidStr)) return ve('INVALID_TYPE', 'service_id must be a positive integer');
const service_id = parseInt(sidStr);
if (service_id < 1) return ve('INVALID_TYPE', 'service_id must be >= 1');

const start_time = String(input.start_time || '').trim();
if (!start_time) return ve('MISSING_FIELD', 'start_time is required');
if (!isIsoDate(start_time)) return ve('INVALID_TYPE', 'start_time must be ISO 8601 with timezone (e.g. 2026-04-15T09:00:00-03:00)');
const startDate = new Date(start_time);
if (isNaN(startDate.getTime())) return ve('INVALID_DATE', 'start_time is not a valid date');

let end_time = start_time;
if (input.end_time !== undefined && input.end_time !== null) {
  end_time = String(input.end_time).trim();
  if (!isIsoDate(end_time)) return ve('INVALID_TYPE', 'end_time must be ISO 8601 with timezone');
  const endDate = new Date(end_time);
  if (isNaN(endDate.getTime())) return ve('INVALID_DATE', 'end_time is not a valid date');
  if (endDate <= startDate) return ve('INVALID_RANGE', 'end_time must be after start_time');
}

let chat_id = null;
if (input.chat_id !== undefined && input.chat_id !== null) {
  const cidStr = String(input.chat_id).trim();
  if (!isNonNegativeInt(cidStr)) return ve('INVALID_TYPE', 'chat_id must be a non-negative integer');
  chat_id = parseInt(cidStr);
}

let gcal_event_id = null;
if (input.gcal_event_id !== undefined && input.gcal_event_id !== null) {
  gcal_event_id = String(input.gcal_event_id).trim();
  if (!isSafeStr(gcal_event_id)) return ve('INVALID_INPUT', 'gcal_event_id contains invalid chars or exceeds 255 chars');
}

let status = 'CONFIRMED';
if (input.status !== undefined && input.status !== null) {
  status = String(input.status).toUpperCase().trim();
  const VALID = ['CONFIRMED', 'CANCELLED', 'RESCHEDULED', 'COMPLETED', 'NO_SHOW'];
  if (!VALID.includes(status)) return ve('INVALID_TYPE', 'status must be one of: ' + VALID.join(', '));
}

return [{ json: {
  ...raw,
  success: true, idempotency_key, provider_id, service_id,
  start_time, end_time, chat_id, gcal_event_id, status, _validated: true
}}];

// Gate: _exit_early items get harmless query
// Valid items: build idempotency check (§3.3 Layer 3)
const input = $input.first().json;

if (input._exit_early) {
  return [{ json: { ...input, idempotency_check_query: "SELECT NULL AS id, NULL AS status WHERE FALSE;" } }];
}

const esc = (v) => v.replace(/\\/g, '\\\\').replace(/'/g, "''").substring(0, 255);
const check_query = `SELECT id, status FROM bookings WHERE idempotency_key = '${esc(input.idempotency_key)}'::text LIMIT 1;`;

return [{ json: { ...input, idempotency_check_query: check_query } }];

// Handle DB error during idempotency check
const e = $input.first().json;
const upstreamData = $('Build Idempotency Check Query').isExecuted ? $('Build Idempotency Check Query').first().json : {};
let error_code = 'IDEMPOTENCY_CHECK_FAILED';
let error_message = e.message || e.error?.message || 'Failed to check idempotency';

if (error_message.includes('connection') || error_message.includes('ECONNREFUSED')) {
  error_code = 'DB_CONNECTION_ERROR';
  error_message = 'Database connection failed during idempotency check';
} else if (error_message.includes('timeout') || error_message.includes('ETIMEDOUT')) {
  error_code = 'DB_TIMEOUT';
  error_message = 'Database timeout during idempotency check';
} else if (error_message.includes('authentication')) {
  error_code = 'DB_AUTH_ERROR';
}

return [{ json: {
  ...upstreamData,
  success: false, error_code, error_message, data: null,
  _meta: { source: 'DB_Create_Booking', timestamp: new Date().toISOString(), workflow_id: $workflow.id }
}}];

const pgResult = $input.first().json;
const upstreamData = $('Build Idempotency Check Query').isExecuted
  ? $('Build Idempotency Check Query').first().json
  : null;

if (upstreamData && upstreamData._exit_early) {
  return [{ json: { ...upstreamData, _route: 'error' } }];
}

const originalData = upstreamData && upstreamData._validated ? upstreamData : null;
if (!originalData) {
  return [{ json: {
    success: false, error_code: 'PIPELINE_ERROR',
    error_message: 'Validated data lost in Route By Idempotency',
    data: null, _route: 'error',
    _meta: { source: 'DB_Create_Booking', timestamp: new Date().toISOString(), workflow_id: $workflow.id }
  }}];
}

const hasExisting = pgResult && pgResult.id !== undefined && pgResult.id !== null;
if (hasExisting) {
  return [{ json: {
    success: true, error_code: null, error_message: null,
    data: { booking_id: pgResult.id, status: pgResult.status || 'CONFIRMED', is_duplicate: true },
    _meta: { source: 'DB_Create_Booking', timestamp: new Date().toISOString(), workflow_id: $workflow.id },
    _route: 'existing'
  }}];
}

return [{ json: { ...originalData, _route: 'new' } }];

// GATE: Only build query for _route === 'new'
const input = $input.first().json;
const { provider_id, service_id, start_time, end_time, idempotency_key, gcal_event_id, chat_id, status } = input;
const esc = (v) => v.replace(/\\/g, '\\\\').replace(/'/g, "''").substring(0, 255);

const insert_query = `INSERT INTO bookings (
  provider_id, service_id, start_time, end_time,
  idempotency_key, gcal_event_id, user_id, status, created_at
) VALUES (
  ${Number(provider_id)}::int,
  ${Number(service_id)}::int,
  '${esc(start_time)}'::timestamptz,
  '${esc(end_time)}'::timestamptz,
  '${esc(idempotency_key)}'::text,
  ${gcal_event_id ? `'${esc(gcal_event_id)}'::text` : 'NULL'},
  ${chat_id !== null ? `${Number(chat_id)}::bigint` : 'NULL'},
  '${esc(status)}'::text,
  NOW()
) RETURNING id, status;`;

return [{ json: { ...input, insert_query } }];

// Format success — new booking created
const result = $input.first().json;
const upstreamData = $('Build Insert Query').isExecuted ? $('Build Insert Query').first().json : {};
const booking_id = result.id || null;

if (!booking_id) {
  return [{ json: {
    ...upstreamData,
    success: false, error_code: 'DB_ERROR',
    error_message: 'INSERT succeeded but no booking_id returned',
    data: null,
    _meta: { source: 'DB_Create_Booking', timestamp: new Date().toISOString(), workflow_id: $workflow.id }
  }}];
}

return [{ json: {
  ...upstreamData,
  success: true, error_code: null, error_message: null,
  data: { booking_id, status: result.status || 'CONFIRMED', is_duplicate: false },
  _meta: { source: 'DB_Create_Booking', timestamp: new Date().toISOString(), workflow_id: $workflow.id }
}}];

// Handle INSERT error — categorize
const e = $input.first().json;
const upstreamData = $('Build Insert Query').isExecuted ? $('Build Insert Query').first().json : {};
let error_code = 'DB_INSERT_ERROR';
let error_message = e.message || e.error?.message || 'Failed to create booking';

if (error_message.includes('violates foreign key')) {
  error_code = 'FK_VIOLATION';
  if (error_message.includes('provider')) error_message = 'Invalid provider_id: provider does not exist';
  else if (error_message.includes('service')) error_message = 'Invalid service_id: service does not exist';
  else error_message = 'Foreign key constraint violation';
} else if (error_message.includes('idempotency_key') && (error_message.includes('already exists') || error_message.includes('duplicate key'))) {
  error_code = 'DUPLICATE_IDEMPOTENCY_KEY';
  error_message = 'Booking with this idempotency_key already exists (race condition)';
} else if (error_message.includes('connection') || error_message.includes('ECONNREFUSED')) {
  error_code = 'DB_CONNECTION_ERROR';
} else if (error_message.includes('timeout') || error_message.includes('ETIMEDOUT')) {
  error_code = 'DB_TIMEOUT';
}

return [{ json: {
  ...upstreamData,
  success: false, error_code, error_message, data: null,
  _meta: { source: 'DB_Create_Booking', timestamp: new Date().toISOString(), workflow_id: $workflow.id }
}}];

const items = $input.all();
if (!items || items.length === 0) return [{ json: { success: false, error_code: 'EMPTY_RESULT', error_message: 'Expected items but got none' } }];
const input = items[0].json;
return [{ json: {
  success: input.success === true,
  error_code: input.error_code || null,
  error_message: input.error_message || null,
  data: input.data || null,
  _meta: input._meta || {
    source: 'DB_Create_Booking', timestamp: new Date().toISOString(), workflow_id: $workflow.id
  }
}}];
